// Normalize OpenAI response into flat preference fields
const item = items[0] || { json: {} };
const source = item.json || {};
const rawMessage = source?.choices?.[0]?.message?.content?.[0]?.text
  ?? source?.data?.[0]?.content?.[0]?.text
  ?? source?.text
  ?? source?.message
  ?? source;

let parsed = {};
let parseError = '';

try {
  parsed = typeof rawMessage === 'string' ? JSON.parse(rawMessage) : (rawMessage || {});
} catch (error) {
  parseError = error.message;
}

const maxTime = Number(parsed.max_time_minutes);

return [{
  json: {
    ingredients: parsed.ingredients || '',
    cuisine_preference: parsed.cuisine_preference || 'any',
    max_time_minutes: Number.isFinite(maxTime) ? maxTime : null,
    parse_error: parseError
  }
}];

// Format the first recipe result coming from Edamam
const itemsIn = Array.isArray(items) ? items : [];
const first = (itemsIn[0] || {}).json || {};
const hits = Array.isArray(first.hits) ? first.hits : [];

if (!hits.length || !hits[0].recipe) {
  return [{
    json: {
      title: 'No recipes found',
      imageUrl: '',
      recipeUrl: '',
      calories: 0,
      ingredientCount: 0,
      note: 'No recipes matched your request. Try different ingredients or tweak cuisine/time preferences.'
    }
  }];
}

const recipe = hits[0].recipe;

return [{
  json: {
    title: recipe.label || 'Recipe',
    imageUrl: recipe.image || '',
    recipeUrl: recipe.url || '',
    calories: Math.round(recipe.calories || 0),
    ingredientCount: Array.isArray(recipe.ingredientLines) ? recipe.ingredientLines.length : 0
  }
}];
